import{_ as a,o,c as n,ag as t}from"./chunks/framework.CAXxHpAX.js";const i=JSON.parse('{"title":"默写抗日战争胜利的意义","description":"","frontmatter":{},"headers":[],"relativePath":"notes/note-15.md","filePath":"notes/note-15.md"}'),r={name:"notes/note-15.md"};function s(e,p,l,c,d,b){return o(),n("div",null,[...p[0]||(p[0]=[t('<h1 id="默写抗日战争胜利的意义" tabindex="-1">默写抗日战争胜利的意义 <a class="header-anchor" href="#默写抗日战争胜利的意义" aria-label="Permalink to &quot;默写抗日战争胜利的意义&quot;">​</a></h1><p>默写抗日战争胜利的意义</p><p>1、女真族的首领是J完颜阿骨打</p><p>2、建立元朝的是H忽必烈</p><p>3、改国号改族名为清的是A皇太极</p><p>4、设置军机处的是 I雍正</p><p>5、签订《尼布楚条约》的是 D康熙</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、唐朝对西域的管理：</span></p><p>①唐太宗打败东、西突厥；</p><p>②设置安西都护府、北庭都护府</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、元朝的中央机构有哪三个？行政：</span>中书省 军事：枢密院 监察：御史台</p><p>8、宋朝海上丝绸之路最远到达哪里？非洲东海岸和阿拉伯半岛</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">郑和：</span>非洲东海岸和红海沿岸</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、长篇章回体小数的开山之作：</span>D《三国演义》</p><p>1</p><p>0、以下哪些发明由阿拉伯人传播到欧洲？B指南针C火药</p><p>A活字印刷术（蒙古人西征）</p><p>1、契丹族的首领是 E耶律阿保机</p><p>2、建立元朝的是H忽必烈</p><p>3、改国号改族名为清的是A皇太极</p><p>4、设置南书房的是D康熙</p><p>5、蒙古族的土尔扈特部首领渥巴锡回归是K乾隆</p><p>B铁木真（统一蒙古草原） C顺治（册封达赖） F努尔哈赤（建立大金政权） G元昊（西夏族首领） I雍正（军机处、驻藏大臣）</p><p>J完颜阿骨打（金的首领）</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、创立进士科的皇帝是：</span> B隋炀帝</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、大运河的目的：</span>加强南北交通，巩固隋对全国的统治</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、唐朝的西域的管理方式有：</span>太宗打败东、西突厥；设安西都护府和北庭都护府</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">9、元朝的中央机构有哪三个？行政：</span>中书省 军事：枢密院 监察：御史台</p><p>1</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">0、中国十七世纪工业百科全书是：</span>《天工开物》 作者是：宋应星</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、辽宋夏金元时期（目录标题）：</span>民族关系发展和社会变化</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">2、经济中心南移：</span> 唐末安史之乱（开始）—— 南宋（结束）</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">3、郑和下西洋的时间：</span>1405-1433</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、《农政全书》的作者：</span>徐光启</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">5、《资治通鉴》朝代：</span>北宋 记述战国-五代</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、唐朝农业发展的表现（2点）：</span>曲辕犁、筒车</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">7、科举制正式创立的皇帝：</span>隋炀帝</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">8、清朝雍正对西南地区的管理措施：</span>驻藏大臣</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">清朝疆域四至：</span>西跨9（ 葱岭），北接10（ 西伯利亚 ），东临太平洋，南到南海诸岛。</p><p>1</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">1、新文化运动的作用：</span>动摇了封建道德礼教的统治地位，使人民接受了一次民主科学的洗礼，对五四运动的爆发齐了思想宣传和铺垫作用，打开了遏制新思想涌流的闸门，掀起了一股思想解放的潮流，白话文普及开来。</p><p>1、唐朝书法家是？颜真卿、柳公权、欧阳询</p><p>2、五代十国的实质是什么？藩镇割据的延续</p><p>3、为加强对地方财权的管理，宋太祖怎么做？设置转运使，把地方财政收归中央。</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">4、清朝疆域四至：</span>西跨葱岭，北接西伯利亚 ，东临太平洋，南到南海诸岛。</p><p>5、郑和的船队最远到达哪里？非洲东海岸和红海沿岸</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">6、元朝的建立者是？腹里归谁管理？忽必烈 中书省（腹里：</span>山东、山西、河北）</p><p>7、元朝哪个地方首次并入中央管辖？台湾，澎湖巡检司（东南）、西藏，宣政院、宣慰使司都元帅府（西南）</p><p>8、北宋哪里最繁华？开封大相国寺</p><p>9、明朝戏剧家和代表作？汤显祖《牡丹亭》</p><p>1</p><p><span style="color:var(--vp-c-brand-1);font-weight:bold;">0、清朝对新疆地区的管辖措施有？康熙：</span>平定准噶尔叛乱；乾隆：平定大小和卓、设置伊犁将军、哨所、安置土尔扈特部；左宗棠收复新疆，1884年新疆设省。</p>',52)])])}const f=a(r,[["render",s]]);export{i as __pageData,f as default};
